<template><el-card v-if="data"><template #header><div class="head"><b>居住登记信息</b><div><el-button @click="print">打印信息页</el-button><el-button v-if="data.status==='ACTIVE'&&user.hasPermission('residence-permit:apply')" type="primary" @click="apply">首次申领居住证</el-button><el-button v-if="data.status==='ACTIVE'&&user.hasPermission('floating:close')" type="danger" @click="close">关闭登记</el-button></div></div></template><el-descriptions border :column="2"><el-descriptions-item v-for="(v,k) in data" :key="k" :label="k">{{v}}</el-descriptions-item></el-descriptions><el-alert class="notice" title="课程模拟系统生成，不作为真实政务证件" type="warning" show-icon/></el-card></template>
<script setup>import{ref,onMounted}from'vue';import{useRoute,useRouter}from'vue-router';import{ElMessageBox,ElMessage}from'element-plus';import{getFloatingPopulation,closeFloating}from'../../api/floatingResidence';import{useUserStore}from'../../stores/user';const route=useRoute(),router=useRouter(),user=useUserStore(),data=ref();onMounted(async()=>data.value=await getFloatingPopulation(route.params.id));function print(){window.print()}function apply(){router.push({path:'/residence-permits/applications/first-issue',query:{floatingId:data.value.floatingId}})}async function close(){const comment=await ElMessageBox.prompt('请输入关闭原因说明','关闭登记');await closeFloating(data.value.floatingId,{reasonCode:'LEFT_REGION',comment:comment.value,version:data.value.version});ElMessage.success('登记已关闭');data.value=await getFloatingPopulation(route.params.id)}</script><style scoped>.head{display:flex;justify-content:space-between}.notice{margin-top:18px}</style>
